/// <summary>
/// this method Handles the lookup event for the PurchAgreementHeader_VendAccount1 control.
/// This method sets up a customized lookup for vendor account information
/// </summary>
/// <param name="sender">The form control that initiated the event</param>
/// <param name="e">The event arguments</param>
[FormControlEventHandler(formControlStr(PurchAgreementCreate, PurchAgreementHeader_VendAccount1), FormControlEventType::Lookup)]
public static void PurchAgreementHeader_VendAccount1_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(ETGACFParameters::find().EnableUATSmallPoints == NoYes::Yes)
    {
        SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(ETGVendLookupView),sender);
        Query                   q   = new Query();
        QueryBuildDataSource    qbds;
        QueryBuildRange         qbr;

        qbds   = q.addDataSource(tableNum(ETGVendLookupView));

        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, AccountNum));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, Name));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, NameAlias));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, VendGroup));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, City));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, State));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, CountryRegionId));
        sysTableLookup.addLookupfield(fieldNum(ETGVendLookupView, ZipCode));
        SysTableLookup.parmQuery(q);
        SysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;
        ce.CancelSuperCall();
    }

}
